from pico_fastapi import controller, get, post
from schemas import ItemResponse, ItemListResponse

@controller(prefix="/api/items")
class ItemController:
    @get("/", response_model=ItemListResponse)
    def list_items(self):
        return {"items": [{"id": 1, "name": "Widget", "price": 9.99}], "total": 1}

    @get("/{item_id}", response_model=ItemResponse)
    def get_item(self, item_id: int):
        return {"id": item_id, "name": "Widget", "price": 9.99}

    @post("/", status_code=201, response_model=ItemResponse)
    def create_item(self, name: str, price: float):
        return {"id": 42, "name": name, "price": price}

